I'm using this mixin for ordering. 

```python
class QueryOrderableViewSetMixin(object):

    def get_queryset(self):
        queryset = super(QueryOrderableViewSetMixin, self).get_queryset()
        try:
            order_by = self.request.query_params['order_by']
            return queryset.order_by(*order_by.split(','))
        except KeyError:
            return queryset

Here is a pattern that worked for me for splitting into multiple files.

Note: I'm brand new to flask and restplus, so not sure if this is right, but since I had trouble finding any examples of how to do this, thought I'd share a complete example here.

Note: prats is a copy of stats with a different name, just to show how you can have different endpoints described in different files

First the tree:
```
├── app.py
└── views
    ├── api.py
    ├── __init__.py
    ├── prats.py
    └── stats.py
```

app.py
note: trick is to import statsApi and pratsApi, even though you don't use them. The import builds the blueprint.
```
from flask import Flask
from flask.ext.cors import CORS
from views.api import apiv1
from views.stats import api as statsApi
from views.prats import api as pratsApi


app = Flask(__name__)
app.register_blueprint(apiv1)

cors = CORS(app, resources={r"/v1/*": {"origins": "*"}})


@app.after_request
def after_request(response):
    response.headers.add('Access-Control-Allow-Origin', '*')
    response.headers.add('Access-Control-Allow-Headers', 'Content-Type,Authorization')
    response.headers.add('Access-Control-Allow-Methods', 'GET,PUT,POST,DELETE')
    return response

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')
```

views/api.py
```
from flask import Blueprint
from flask.ext.restplus import Api


apiv1 = Blueprint('api', __name__, url_prefix='/v1')
api = Api(apiv1, version='1.0', title='POC API',
          description='Proof of Concept API')
stats_ns = api.namespace('stats', 'Stats methods')
prats_ns = api.namespace('prats', 'Prats methods')
```

views/stats.py
```
from flask.ext.restplus import Resource, fields
from collections import OrderedDict
from views.api import api, stats_ns


STATS = OrderedDict([
    ('1', {'statId': '1', 'name': 'davetime', 'value': 10}),
    ('2', {'statId': '2', 'name': 'gregtime', 'value': 20}),
    ('3', {'statId': '3', 'name': 'kevintime', 'value': 30}),
])

stat_fields = {
    'statId': fields.String(required=True, description='The statId of the stat'),
    'name': fields.String(required=True, description='The name of the stat'),
    'value': fields.String(required=True, description='The value of the stat'),
}
stat = api.model('Stat', stat_fields)
statList = api.model('StatList', {
    'results': fields.Nested(stat, description='Array of stat')
})


def abort_if_stat_doesnt_exist(statId):
    if statId not in STATS:
        api.abort(404, message="Stat {} doesn't exist".format(statId))

parser = api.parser()
parser.add_argument('name', type=str, required=True, help='Name of the stat', location='form')
parser.add_argument('value', type=str, required=True, help='Value of the stat', location='form')


@stats_ns.route('/<string:statId>/')
@api.doc(responses={404: 'Stat not found'}, params={'statId': 'The statId of the stat'})
class Stat(Resource):
    """
    shows a single stat item and lets you delete a stat item
    """
    @api.doc(description='Get a stat', responses={200: 'Ok'})
    @api.marshal_with(stat)
    def get(self, statId):
        abort_if_stat_doesnt_exist(statId)
        return STATS[statId]

    @api.doc(responses={204: 'Stat deleted'})
    def delete(self, statId):
        abort_if_stat_doesnt_exist(statId)
        del STATS[statId]
        return '', 204

    @api.doc(parser=parser)
    @api.marshal_with(stat)
    def put(self, statId):
        abort_if_stat_doesnt_exist(statId)
        args = parser.parse_args()
        stat = STATS[statId]
        for item in args.keys():
            if item in stat.keys() and args[item] is not None:
                stat[item] = args[item]
        STATS[statId] = stat
        return stat, 201


@stats_ns.route('/')
class StatList(Resource):
    """
    shows a list of all stats, and lets you POST to add new stats
    """
    @api.doc(description='Get a list of stats')
    @api.marshal_with(statList)
    def get(self):
        return self._get_stats()

    def _get_stats(self):
        context = {'results': []}
        for statId in sorted(STATS.keys()):
            context['results'].append(STATS[statId])
        return context

    @api.doc(parser=parser)
    @api.marshal_with(stat, code=201)
    def post(self):
        args = parser.parse_args()
        statId = '{}'.format(int(max(STATS.keys()))+1)
        STATS[statId] = {'statId': statId, 'name': args['name'],  'value': args['value']}
        return STATS[statId], 201
```

views/prats.py
```
from flask.ext.restplus import Resource, fields
from collections import OrderedDict
from views.api import api, prats_ns


PRATS = OrderedDict([
    ('1', {'pratId': '1', 'name': 'davetime', 'value': 10}),
    ('2', {'pratId': '2', 'name': 'gregtime', 'value': 20}),
    ('3', {'pratId': '3', 'name': 'kevintime', 'value': 30}),
])

prat_fields = {
    'pratId': fields.String(required=True, description='The pratId of the prat'),
    'name': fields.String(required=True, description='The name of the prat'),
    'value': fields.String(required=True, description='The value of the prat'),
}
prat = api.model('Prat', prat_fields)
pratList = api.model('PratList', {
    'results': fields.Nested(prat, description='Array of prat')
})


def abort_if_prat_doesnt_exist(pratId):
    if pratId not in PRATS:
        api.abort(404, message="Prat {} doesn't exist".format(pratId))

parser = api.parser()
parser.add_argument('name', type=str, required=True, help='Name of the prat', location='form')
parser.add_argument('value', type=str, required=True, help='Value of the prat', location='form')


@prats_ns.route('/<string:pratId>/')
@api.doc(responses={404: 'Prat not found'}, params={'pratId': 'The pratId of the prat'})
class Prat(Resource):
    """
    shows a single prat item and lets you delete a prat item
    """
    @api.doc(description='Get a prat', responses={200: 'Ok'})
    @api.marshal_with(prat)
    def get(self, pratId):
        abort_if_prat_doesnt_exist(pratId)
        return PRATS[pratId]

    @api.doc(responses={204: 'Prat deleted'})
    def delete(self, pratId):
        abort_if_prat_doesnt_exist(pratId)
        del PRATS[pratId]
        return '', 204

    @api.doc(parser=parser)
    @api.marshal_with(prat)
    def put(self, pratId):
        abort_if_prat_doesnt_exist(pratId)
        args = parser.parse_args()
        prat = PRATS[pratId]
        for item in args.keys():
            if item in prat.keys() and args[item] is not None:
                prat[item] = args[item]
        PRATS[pratId] = prat
        return prat, 201


@prats_ns.route('/')
class PratList(Resource):
    """
    shows a list of all prats, and lets you POST to add new prats
    """
    @api.doc(description='Get a list of prats')
    @api.marshal_with(pratList)
    def get(self):
        return self._get_prats()

    def _get_prats(self):
        context = {'results': []}
        for pratId in sorted(PRATS.keys()):
            context['results'].append(PRATS[pratId])
        return context

    @api.doc(parser=parser)
    @api.marshal_with(prat, code=201)
    def post(self):
        args = parser.parse_args()
        pratId = '{}'.format(int(max(PRATS.keys()))+1)
        PRATS[pratId] = {'pratId': pratId, 'name': args['name'],  'value': args['value']}
        return PRATS[pratId], 201
```

