```python
@gen.coroutine 
def recv_handler(sock, events):
    while True:
        try:
            events = yield sock.poll(timeout=5)
            if events& zmq.POLLIN:
                client_id, message =  yield sock.recv_multipart()
                if message:
                    yield sock.send_multipart( [client_id, message] )
                    print( f"id:{client_id}, request:{len(message)}" )
        except zmq.error.ZMQError as e:
            print (traceback.format_exc())
        except KeyboardInterrupt:
            break # Interrupted  
