OK - I have a system using `find src/rust/engine -type f | git hash-object` that can calculate a full directory tree hash efficiently that gives ~15ms noops vs just letting cargo noop on a single file which takes ~400ms.

Basically:
```bash
#!/usr/bin/env bash

REPO_ROOT=$(cd $(dirname "${BASH_SOURCE[0]}") && cd .. && pwd -P)

NATIVE_ROOT="${REPO_ROOT}/src/rust/engine"
MODE=debug
MODE_FLAG=

# TODO(John Sirois): Handle platform dirs, extension (ie: .{dylib,so}) and version.
EXTENSION=so
OS=linux
PLATFORM=x86_64
VERSION=0.0.1

CACHE_TARGET_DIR=~/.cache/pants/${EXTENSION}/native-engine/${OS}/${PLATFORM}/${VERSION}

function calculate_current_hash() {
  find src/java -type f | git hash-object -t blob --stdin-paths | sha1sum | cut -d' ' -f1
}

function read_built_at_hash() {
  cat ${CACHE_TARGET_DIR}/built_at_hash 2>/dev/null
}

function write_built_at_hash() {
  echo $1 > ${CACHE_TARGET_DIR}/built_at_hash
}

function bootstrap_native_code() {
  current_hash=$(calculate_current_hash)
  if [[ "${current_hash}" != "$(read_built_at_hash)" ]]
  then
    cargo build --manifest-path ${NATIVE_ROOT}/Cargo.toml ${MODE_FLAG}
    mkdir -p ${CACHE_TARGET_DIR}
    ln -f ${NATIVE_ROOT}/target/${MODE}/libengine.${EXTENSION} ${CACHE_TARGET_DIR}/native-engine
    write_built_at_hash ${current_hash}
  fi
}
```

I just need to work out some details related to platform identifiers and shared library extension. I may be able to hack around both with enough perf to circle back.

