`def convertToInt(x):
    multDict = {
        "k" : 1000,
        "m" : 1000000,
        "b" : 1000000000,
    }
    try :
        y = int(x)
        return y
    except :
        pass
    
    try :
        y = float(str(x)[:-1])
        y = y * multDict[str(x)[-1:].lower()]
        return int(y)
    except :
        pass

    return 0

def media(ur):
